const raw = $input.item.json.stdout || '';
try {
  const d = JSON.parse(raw);
  const verdict = d.verdict || d.status || 'UNKNOWN';
  const icon = verdict === 'GO' ? '✅' : verdict === 'NO-GO' ? '🔴' : '⚠️';
  let msg = `${icon} *Wave ${d.wave || '1'} Readiness — ${verdict}*\n`;
  if (d.blockers && d.blockers.length) {
    msg += `\n*Blockers (${d.blockers.length}):*\n`;
    for (const b of d.blockers.slice(0, 5)) msg += `• ${b}\n`;
  }
  if (d.ready_items && d.ready_items.length) {
    msg += `\n*Ready:* ${d.ready_items.length} items`;
  }
  return [{ json: { text: msg, verdict } }];
} catch (e) {
  return [{ json: { text: `⚠️ *Wave Readiness*\n\n${raw.substring(0, 2000) || 'No output.'}`, verdict: 'UNKNOWN' } }];
}
